1в†’import { useEffect, useRef } from 'react'
2в†’import * as THREE from 'three'
3в†’
4в†’export default function HeroScene3D() {
5в†’  const mountRef = useRef(null)
6в†’
7в†’  useEffect(() => {
8в†’    const container = mountRef.current
9в†’    if (!container) return
10в†’
11в†’    // Respect reduced motion
12в†’    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches
13в†’    const isMobile = window.innerWidth < 768
14в†’
15в†’    // Scene setup
16в†’    const scene = new THREE.Scene()
17в†’    const W = container.clientWidth
18в†’    const H = container.clientHeight
19в†’
20в†’    const camera = new THREE.PerspectiveCamera(55, W / H, 0.1, 100)
21в†’    camera.position.z = 7
22в†’    camera.position.x = 1.2
23в†’
24в†’    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: !isMobile })
25в†’    renderer.setSize(W, H)
26в†’    renderer.setPixelRatio(Math.min(window.devicePixelRatio, isMobile ? 1 : 2))
27в†’    renderer.setClearColor(0x000000, 0)
28в†’    container.appendChild(renderer.domElement)
29в†’
30в†’    // Colors matching portfolio palette
31в†’    const C1 = new THREE.Color('#38bdf8') // sky
32в†’    const C2 = new THREE.Color('#a78bfa') // violet
33в†’    const C3 = new THREE.Color('#f472b6') // pink
34в†’    const C4 = new THREE.Color('#34d399') // emerald
35в†’
36в†’    // в”Ђв”Ђ Main TorusKnot в”Ђв”Ђ
37в†’    const torusGeo = new THREE.TorusKnotGeometry(1.0, 0.3, isMobile ? 64 : 128, isMobile ? 8 : 24)
38в†’    const torusMat = new THREE.MeshBasicMaterial({
39в†’      color: C1,
40в†’      wireframe: true,
41в†’      transparent: true,
42в†’      opacity: 0.1,
43в†’    })
44в†’    const torusKnot = new THREE.Mesh(torusGeo, torusMat)
45в†’    scene.add(torusKnot)
46в†’
47в†’    // Inner glow mesh (solid, very transparent)
48в†’    const glowMat = new THREE.MeshBasicMaterial({
49в†’      color: C2,
50в†’      transparent: true,
51в†’      opacity: 0.02,
52в†’      side: THREE.DoubleSide,
53в†’    })
54в†’    const glowMesh = new THREE.Mesh(torusGeo, glowMat)
55в†’    scene.add(glowMesh)
56в†’
57в†’    // в”Ђв”Ђ Orbiting Icosahedrons в”Ђв”Ђ
58в†’    const orbiters = []
59в†’    const orbiterCount = isMobile ? 3 : 6
60в†’    const orbiterColors = [C1, C2, C3, C4, C1, C3]
61в†’    for (let i = 0; i < orbiterCount; i++) {
62в†’      const size = 0.08 + Math.random() * 0.12
63в†’      const geo = new THREE.IcosahedronGeometry(size, 0)
64в†’      const mat = new THREE.MeshBasicMaterial({
65в†’        color: orbiterColors[i % orbiterColors.length],
66в†’        wireframe: true,
67в†’        transparent: true,
68в†’        opacity: 0.25,
69в†’      })
70в†’      const mesh = new THREE.Mesh(geo, mat)
71в†’
72в†’      // Orbit parameters
73в†’      const orbit = {
74в†’        mesh,
75в†’        radius: 2.2 + Math.random() * 1.2,
76в†’        speed: 0.3 + Math.random() * 0.5,
77в†’        phase: (Math.PI * 2 * i) / orbiterCount + Math.random() * 0.5,
78в†’        tilt: Math.random() * Math.PI * 0.5,
79в†’        rotSpeed: 0.5 + Math.random() * 1.5,
80в†’      }
81в†’      orbiters.push(orbit)
82в†’      scene.add(mesh)
83в†’    }
84в†’
85в†’    // в”Ђв”Ђ Floating particles в”Ђв”Ђ
86в†’    const particleCount = isMobile ? 30 : 80
87в†’    const particleGeo = new THREE.BufferGeometry()
88в†’    const particlePositions = new Float32Array(particleCount * 3)
89в†’    const particleSizes = new Float32Array(particleCount)
90в†’    for (let i = 0; i < particleCount; i++) {
91в†’      particlePositions[i * 3] = (Math.random() - 0.5) * 10
92в†’      particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 10
93в†’      particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 6
94в†’      particleSizes[i] = Math.random() * 3 + 1
95в†’    }
96в†’    particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3))
97в†’    particleGeo.setAttribute('size', new THREE.BufferAttribute(particleSizes, 1))
98в†’    const particleMat = new THREE.PointsMaterial({
99в†’      color: C1,
100в†’      size: 0.03,
101в†’      transparent: true,
102в†’      opacity: 0.4,
103в†’      sizeAttenuation: true,
104в†’    })
105в†’    const particles = new THREE.Points(particleGeo, particleMat)
106в†’    scene.add(particles)
107в†’
108в†’    // в”Ђв”Ђ Mouse tracking в”Ђв”Ђ
109в†’    const mouse = { x: 0, y: 0, targetX: 0, targetY: 0 }
110в†’    const onMouseMove = (e) => {
111в†’      mouse.targetX = (e.clientX / window.innerWidth) * 2 - 1
112в†’      mouse.targetY = -(e.clientY / window.innerHeight) * 2 + 1
113в†’    }
114в†’    window.addEventListener('mousemove', onMouseMove)
115в†’
116в†’    // в”Ђв”Ђ Animation в”Ђв”Ђ
117в†’    const clock = new THREE.Clock()
118в†’    let animId
119в†’
120в†’    function animate() {
121в†’      animId = requestAnimationFrame(animate)
122в†’      const t = clock.getElapsedTime()
123в†’      const speed = prefersReduced ? 0.15 : 1
124в†’
125в†’      // Smooth mouse interpolation
126в†’      mouse.x += (mouse.targetX - mouse.x) * 0.04
127в†’      mouse.y += (mouse.targetY - mouse.y) * 0.04
128в†’
129в†’      // Main torusKnot rotation + mouse tilt
130в†’      torusKnot.rotation.x = t * 0.12 * speed + mouse.y * 0.3
131в†’      torusKnot.rotation.y = t * 0.18 * speed + mouse.x * 0.3
132в†’      torusKnot.rotation.z = t * 0.06 * speed
133в†’
134в†’      // Pulse opacity
135в†’      torusMat.opacity = 0.08 + Math.sin(t * 0.8) * 0.04
136в†’      glowMat.opacity = 0.015 + Math.sin(t * 0.5) * 0.01
137в†’
138в†’      // Glow mesh follows with slight lag
139в†’      glowMesh.rotation.copy(torusKnot.rotation)
140в†’      glowMesh.rotation.x += 0.1
141в†’      glowMesh.rotation.y += 0.15
142в†’
143в†’      // Orbiting icosahedrons
144в†’      orbiters.forEach((o) => {
145в†’        const angle = t * o.speed * speed + o.phase
146в†’        o.mesh.position.x = Math.cos(angle) * o.radius
147в†’        o.mesh.position.y = Math.sin(angle) * o.radius * Math.cos(o.tilt)
148в†’        o.mesh.position.z = Math.sin(angle) * o.radius * Math.sin(o.tilt) * 0.5
149в†’        o.mesh.rotation.x = t * o.rotSpeed * speed
150в†’        o.mesh.rotation.y = t * o.rotSpeed * 0.7 * speed
151в†’      })
152в†’
153в†’      // Particles gentle drift
154в†’      const posArr = particles.geometry.attributes.position.array
155в†’      for (let i = 0; i < particleCount; i++) {
156в†’        posArr[i * 3 + 1] += Math.sin(t + i) * 0.001
157в†’        posArr[i * 3] += Math.cos(t * 0.5 + i * 0.3) * 0.0005
158в†’      }
159в†’      particles.geometry.attributes.position.needsUpdate = true
160в†’      particles.rotation.y = t * 0.02 * speed
161в†’
162в†’      // Color cycling
163в†’      const hue = (t * 0.05) % 1
164в†’      torusMat.color.setHSL(hue * 0.15 + 0.55, 0.8, 0.65)
165в†’
166в†’      renderer.render(scene, camera)
167в†’    }
168в†’    animate()
169в†’
170в†’    // в”Ђв”Ђ Resize в”Ђв”Ђ
171в†’    const onResize = () => {
172в†’      const w = container.clientWidth
173в†’      const h = container.clientHeight
174в†’      camera.aspect = w / h
175в†’      camera.updateProjectionMatrix()
176в†’      renderer.setSize(w, h)
177в†’    }
178в†’    window.addEventListener('resize', onResize)
179в†’
180в†’    return () => {
181в†’      cancelAnimationFrame(animId)
182в†’      window.removeEventListener('mousemove', onMouseMove)
183в†’      window.removeEventListener('resize', onResize)
184в†’      renderer.dispose()
185в†’      torusGeo.dispose()
186в†’      torusMat.dispose()
187в†’      glowMat.dispose()
188в†’      particleGeo.dispose()
189в†’      particleMat.dispose()
190в†’      orbiters.forEach((o) => {
191в†’        o.mesh.geometry.dispose()
192в†’        o.mesh.material.dispose()
193в†’      })
194в†’      if (container.contains(renderer.domElement)) {
195в†’        container.removeChild(renderer.domElement)
196в†’      }
197в†’    }
198в†’  }, [])
199в†’
200в†’  return (
201в†’    <div
202в†’      ref={mountRef}
203в†’      style={{
204в†’        position: 'absolute',
205в†’        inset: 0,
206в†’        zIndex: 0,
207в†’        pointerEvents: 'none',
208в†’        overflow: 'hidden',
209в†’      }}
210в†’    />
211в†’  )
212в†’}
